1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const COMPONENT_TYPES = new Set(["rune"]);
13	
14	export function quote(input: { items: Array<{ type: string }> }): { premium: number } {
15	  if (input.items.length === 0) return { premium: PROCESSING_FEE };
16	
17	  const componentCounts: Record<string, number> = {};
18	  let base = 0;
19	  for (const item of input.items) {
20	    if (COMPONENT_TYPES.has(item.type)) {
21	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
22	    } else {
23	      base += BASE_PREMIUMS[item.type];
24	    }
25	  }
26	  for (const [type, count] of Object.entries(componentCounts)) {
27	    base += count === 3 ? 60 : count * BASE_PREMIUMS[type];
28	  }
29	
30	  return { premium: Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE) };
31	}
32	
33	export function claim(_input: unknown): unknown {
34	  return undefined;
35	}
